CREATE TABLE `main_requisition` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `requisition_code` varchar(20) DEFAULT NULL,
  `onboard_date` date DEFAULT NULL,
  `position_id` int DEFAULT NULL,
